let mensaje = "📋 *Tus Solicitudes:* \n\n";

for (const item of $input.first().json.data) {
  // Aquí accedes a los datos de cada fila
  mensaje += `🔹 *ID:* item.id_ticket\n`;
  mensaje += `   *Tipo:* ${item.json.tipo}\n`;
  mensaje += `   *Estado:* ${item.json.estado}\n`;
  mensaje += `   *Descripción:* ${item.json.descripcion}\n`;
  mensaje += "----------------------------\n";
}

return { mensaje };

// 1. Inicializamos una variable para acumular el texto
let listaMensaje = "📋 *Lista de Solicitudes:*\n\n";

// 2. Usamos un bucle for...of para recorrer todos los items de entrada ($input.all())
for (const item of $input.all()) {
  const data = item.json;

  // 3. Vamos sumando la información de cada ticket al mensaje
  // Usamos el operador += para concatenar cada nueva fila
  listaMensaje += `🆔 *Ticket:* ${data.id_ticket}\n`;
  listaMensaje += `🛠️ *Tipo:* ${data.tipo}\n`;
  listaMensaje += `📝 *Descripción:* ${data.descripcion}\n`;
  listaMensaje += `🕒 *Fecha:* ${data.fecha_creacion}\n`;
  listaMensaje += `----------------------------\n`;
}

// 4. Retornamos el objeto final que recibirá el nodo de Telegram
return {
  mensajeCompleto: listaMensaje
};

// 1. Inicializamos variables y contadores
let total = 0;
let porEstado = {};
let porPrioridad = {};
let porTipo = {};

// 2. Procesamos todos los registros del Google Sheet
for (const item of $input.all()) {
  const row = item.json;
  total++;

  // Contar por Estado (ej. Sin resolver, En proceso, Resuelto)
  let estado = row.estado || 'No definido';
  porEstado[estado] = (porEstado[estado] || 0) + 1;

  // Contar por Prioridad (ALTA, MEDIA, BAJA)
  let prioridad = row.prioridad || 'Sin asignar';
  porPrioridad[prioridad] = (porPrioridad[prioridad] || 0) + 1;

  // Contar por Tipo de solicitud
  let tipo = row.tipo || 'General';
  porTipo[tipo] = (porTipo[tipo] || 0) + 1;
}

// 3. Construimos el mensaje para Telegram con un formato profesional
let mensaje = "📊 *REPORTE DE SOLICITUDES*\n";
mensaje += "━━━━━━━━━━━━━━━━━━━━\n\n";
mensaje += `📈 *Total acumulado:* ${total} solicitudes\n\n`;

mensaje += "📌 *ESTADO ACTUAL:*\n";
for (const [key, val] of Object.entries(porEstado)) {
  let icon = key.toLowerCase().includes('resuelto') ? '✅' : '⏳';
  mensaje += `${icon} ${key}: ${val}\n`;
}

mensaje += "\n🔥 *POR PRIORIDAD:*\n";
for (const [key, val] of Object.entries(porPrioridad)) {
  let icon = key === 'ALTA' ? '🔴' : (key === 'MEDIA' ? '🟡' : '🟢');
  mensaje += `${icon} ${key}: ${val}\n`;
}

mensaje += "\n📂 *POR CATEGORÍA:*\n";
for (const [key, val] of Object.entries(porTipo)) {
  mensaje += `• ${key}: ${val}\n`;
}

mensaje += "\n━━━━━━━━━━━━━━━━━━━━\n";
mensaje += `📅 _Corte al: ${new Date().toLocaleString('es-CO')}_`;

// 4. Retornamos el resultado
return {
  mensajeReporte: mensaje,
  datosCrudos: { total, porEstado, porPrioridad, porTipo }
};

